var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"이거 놔! 내가 누군지 알고 내 몸에 손을 대!!","JPN":"放しなさい！　私を誰だと思ってるの！！","ENG":"Let go of me! How dare you touch me! Do you even know who I am?!","TWN":"放開我！你們知道我是誰嗎？竟敢用你們的髒手碰我！！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"네놈들 얼굴 전부 기억해 뒀어! 날 이 따위로 대접한 거 후회하게 만들어 줄 거야!","JPN":"あなたたちの顔、全部覚えておいたわ！　私をこんな風に扱ったこと後悔させてやる！","ENG":"I'll remember all of your ugly faces! You're going to regret this!","TWN":"你們的臉我全都記下了！我會讓你們後悔這樣對我的！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"당장 이 문 열어! 안 열어?!","JPN":"今すぐにこの扉を開けなさい！　早く！！","ENG":"Open this door immediately! I demand that you open! This! Door!","TWN":"立刻把門打開！還不給我開門？！"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRISON_NPC_NULL_NULL","text":{"KOREA":"그건 안 됩니다. 의장님의 지시라서요.","JPN":"それはいけません。議長のご指示ですので。","ENG":"No can do. It's an order from the Chairman himself.","TWN":"恕難從命，這是議長的指示。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"PRISON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"의장님?","JPN":"議長？","ENG":"The Chairman?","TWN":"議長？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"당신, 평의회 사람이었어요? 어휴, 난 그런 줄도 모르고.","JPN":"あなた、評議会の人だったんですか？　まあ、私ったらそんなことも知らないで。","ENG":"Y-you're a member of the Council? Well, why didn't you say so?","TWN":"你是評議會的人嗎？哎呀，是我有眼不識泰山。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"PRISON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"탈옥 사건 얘기는 들었어요. 언제 나갈 수 있는 거죠?","JPN":"脱獄事件の話は聞きました。いつ出られるのかしら。","ENG":"I heard about the jailbreak. So? When will I be released?","TWN":"我有聽說過逃獄事件，那我什麼時候才能出去？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"PRISON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PRISON_NPC_NULL_NULL","text":{"KOREA":"하하, 너무 서두르지 마세요. 감옥 공기를 쐬니 정신이 돌아오셨잖습니까.","JPN":"はは、あまり焦らないでください。牢獄の空気に当たって、正気を取り戻したではありませんか。","ENG":"Haha, what's the hurry? After a whiff of the prison air, you came back to your sense, didn't you?","TWN":"哈哈，別心急，你不是呼吸到監獄的空氣後，精神才恢復正常的嗎？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"PRISON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"이런 불결한 환경에 언제까지 있을 수는 없잖아요.","JPN":"いつまでもこんな不潔なところにいられるわけないじゃないですか。","ENG":"Well, I can't be held up in this filthy place forever, can I?","TWN":"總不能一直待在這種骯髒的環境嘛。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":{"char_id":"PRISON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"들어 봐요. 전 맨손으로 헤이븐 랜드를 세웠어요. 그 사람만 좋은 짐덩이들을 데리고!","JPN":"聞いてください。私は何もないところからヘイブンランドを作ったんです。あの性格だけはいいお荷物たちを連れて！","ENG":"Listen. I built Havenland from the ground up all by myself. And I had to do it while carrying around those dead weight people-loving idiots!","TWN":"你聽我說，是我帶著那些空有一副好心腸的傢伙，一手將天堂樂園建立起來的。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"당신도 헤이븐의 이름은 들었죠? 제 두뇌는 의장님께 아주 큰 힘이 될 거예요.","JPN":"あなたもヘイブンの名前は聞いてるでしょう？　私の頭脳はきっと議長のお役に立つと思います。","ENG":"You've heard of the name Haven, haven't you? My genius will undoubtedly be of great benefit to the Chairman.","TWN":"你也聽過天堂這號人物吧？我的聰明才智對議長會很有幫助的。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"아, 거 쫑알쫑알 되게 시끄럽네.","JPN":"ああ、もうぶつぶつうるさいなあ。","ENG":"Ugh, will you quit yapping already?","TWN":"喂，嘰嘰喳喳地吵什麼啦！"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"……응? 누, 누구야?","JPN":"……うん？　だ、誰？","ENG":"...Huh? W-who're you?","TWN":"……嗯？你…你是誰？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"야, 저 여자 진짜 모르는 눈치다.","JPN":"おい、あの女、本当に知らないみたいだね。","ENG":"Hey, I don't think she knows.","TWN":"喂，那女的真的是目中無人欸！"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"그러게. 되게 서운하네. <color=#ffd34c>우린</color> 언제 오나 계속 기다렸는데.","JPN":"ほんと。悲しいなあ。<color=#ffd34c>私たち</color>はいつ来るかずっと待ってたのに。","ENG":"Yeah. What a shame. <color=#ffd34c>We</color> have been anxiously waiting for you.","TWN":"對啊，真傷心。<color=#ffd34c>我們</color>可是等她進來等很久咧。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"뭐?! 너희들, 날 알아……?","JPN":"え！？　あなたたち、私のことを知ってるのかしら……？","ENG":"What?! Do you know who I am...?","TWN":"什麼？！你們，認識我……？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"당연하지, 헤론.","JPN":"当たり前でしょ、ヘロン。","ENG":"Of course we know you, Heron.","TWN":"當然囉，海倫。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};